#include<bits/stdc++.h>
using namespace std;
int a1[2001],b1[2001],c[20011];
int main()
{
	char a[2001],b[2001],i;
	scanf("%s%s",a,b);
	int lena=strlen(a);
	int lenb=strlen(b);
	for(int i=1;i<=lena;i++)
	{
		a1[i]=a[lena-i]-'0';
	}
	for(int i=1;i<=lenb;i++)
	{
		b1[i]=b[lenb-i]-'0';
	}
	int lenc=1;
	int x=0;
	while(lenc<=lena||lenc<=lenb)
	{
		c[lenc]=a1[lenc]+b1[lenc]+x;
		x=c[lenc]/10;
		c[lenc]%=10;
		lenc++;
	}
	c[lenc]=x;
	while(c[lenc]==0&&lenc>1)
	{
		lenc--;
	}
	for(int i=lenc;i>=1;i--)
	{
		printf("%d",c[i]);
	}
	return 0;
}
